// // This module compares two 4-bit inputs A and B and outputs whether A is less than, greater than, or equal to B.
module magnitude_comparator(  
    input [3:0] A,  
    input [3:0] B,  
    output reg G,  
    output reg L,  
    output reg E  
);  

always @(*) begin  
    if (A > B) begin  
        G = 1;  
        L = 0;  
        E = 0;  
    end else if (A < B) begin  
        G = 0;  
        L = 1;  
        E = 0;  
    end else begin  
        G = 0;  
        L = 0;  
        E = 1;  
    end  
end  

endmodule
